// Este código maneja la verificación de Meta (GET) y los mensajes (POST)
const query = $node["Webhook"].json["query"];
const body = $node["Webhook"].json["body"];

// 1. Si es una solicitud de verificación de Meta (GET)
if (query && query["hub.mode"] === "subscribe") {
    return [{
        json: {
            response: query["hub.challenge"], // Devolvemos el código que Meta espera
            status: 200
        }
    }];
}

// 2. Si es un mensaje real (POST), seguimos con el flujo normal
return [{
    json: {
        body: body,
        routing: { tipo: 'mensaje_recibido' }
    }
}];

// Extraer value del payload anidado
const value = $json.body?.entry?.[0]?.changes?.[0]?.value;

// Detener si es evento de status
if (!value || value.statuses) {
    return [];
}

const message = value.messages?.[0];
const contact = value.contacts?.[0];

if (!message) {
    return [];
}

let docId = null;
if (message.type === 'document') {
    docId = message.document.id;
} else if (message.type === 'image') {
    docId = message.image.id;
}

return [{
    json: {
        from: message.from,
        text: message.text?.body || "",
        name: contact?.profile?.name || "Usuario",
        timestamp: message.timestamp,
        message_id: message.id,
        documentId: docId,
        type: message.type
    }
}];

const texto = $json.text || "";

let limpio = texto
  .replace(/\s+/g, " ")
  .replace(/[^\x20-\x7EáéíóúÁÉÍÓÚñÑ.,;:()\-]/g, "")
  .trim();

const MAX_CHARS = 15000;

const truncado = limpio.length > MAX_CHARS;

if (truncado) {
  limpio = limpio.slice(0, MAX_CHARS);
}

return [{
  telefono: $item(0).$node["normalizar mensaje"].json.from,
  texto_limpio: limpio,
  truncado,
  longitud: limpio.length
}];

// 1️⃣ extraer el texto real del modelo
let raw = $json.output?.[0]?.content?.[0]?.text || "";

// 2️⃣ asegurar string
raw = String(raw);

// 3️⃣ limpiar bloques ```json
raw = raw.replace(/```json/g, "").replace(/```/g, "").trim();

let data;

try {
  data = JSON.parse(raw);
} catch (e) {
  data = {
    valido: false,
    confianza: 0,
    observaciones: "Error interpretando IA"
  };
}

// 4️⃣ regla de seguridad
if ((data.confianza ?? 0) < 50) {
  data.valido = false;
}

return [{
  telefono: $item(0).$node["limpieza"].json.telefono,
  evaluacion: data
}];

let raw = $input.first().json.choices[0].message.content || "🤖 No pude responder.";

return [{
  telefono: $item(0).$node["normalizar mensaje"].json.from,
  respuesta: raw
}];

let rec = $json.output?.[0]?.content?.[0]?.text || "";
const telefono = $item(0).$node["normalizar mensaje"].json.telefono;

return [{
  ...$json,
