const TIEMPO_MUERTO_SEGUNDOS = 10;

const nodoNormalizar = $item(0).$node["normalizar mensaje"].json;
const telefono = nodoNormalizar.from;        // ← era .telefono
const texto_usuario = nodoNormalizar.text;   // ← era .texto_usuario
const es_documento = nodoNormalizar.type;
const documentoId = nodoNormalizar.documentId;

const ahora = new Date();
const registro = $input.first()?.json;

if (!registro || !registro.ultimo_mensaje) {
  return [{ 
    telefono, texto_usuario, es_documento,
    documentoId, bloqueado: false, 
    ahora: ahora.toISOString() 
  }];
}

const ultimoMensaje = new Date(registro.ultimo_mensaje);
const segundosTranscurridos = (ahora - ultimoMensaje) / 1000;

if (segundosTranscurridos < TIEMPO_MUERTO_SEGUNDOS) {
  return [{ 
    telefono, texto_usuario, es_documento,
    documentoId, bloqueado: true, 
    segundos_restantes: Math.ceil(TIEMPO_MUERTO_SEGUNDOS - segundosTranscurridos) 
  }];
}

return [{ 
  telefono, texto_usuario, es_documento,
  documentoId, bloqueado: false, 
  ahora: ahora.toISOString() 
}];

