const telefono = $item(0).$node["extraer_intencion"].json.telefono;
const texto_usuario = $item(0).$node["extraer_intencion"].json.texto_usuario;

// Obtener historial ordenado cronológicamente
const historial = $input.all()
  .map(i => i.json)
  .filter(r => r.rol && r.mensaje)
  .reverse();

// Construir mensajes para el modelo
const mensajes = historial.map(h => ({
  role: h.rol,
  content: h.mensaje
}));

// Agregar mensaje actual del usuario
mensajes.push({
  role: "user",
  content: texto_usuario
});

return [{
  json: {
    telefono,
    texto_usuario,
    mensajes
  }
}];

