  seguimientos = JSON.parse($json.seguimientos_json || "[]");
} catch(e) {}

const seleccionado = seguimientos[opcion - 1];

if (!seleccionado) {
  return [{ json: {
    telefono,
    guardado: false,
    mensaje: `❌ No existe la opción ${opcion}. Elige entre 1 y ${seguimientos.length}.`
  }}];
}

return [{ json: {
  telefono,
  guardado: true,
  id_seguimiento: seleccionado.id_seguimiento,
  mensaje: `✅ Seguimiento ${seleccionado.id_seguimiento} seleccionado.\n\nAhora envía tu bitácora en PDF 📎`
}}];

